def random_scen():
    scen_name = random.choice(list(scenes.keys()))
    scen_xml = scenes[scen_name].strip().replace('\n', ' ').replace('\r', ' ')
    # Remove MessageLog block using string slicing
    start = scen_xml.find('<MessageLog>')
    end = scen_xml.find('</MessageLog>')
    if start != -1 and end != -1:
        scen_xml = scen_xml[:start] + '<MessageLog/>' + scen_xml[end + len('</MessageLog>'):]

    # Reset MessageIncrement to 0
    mi_start = scen_xml.find('<MessageIncrement>')
    mi_end = scen_xml.find('</MessageIncrement>')
    if mi_start != -1 and mi_end != -1:
        scen_xml = scen_xml[:mi_start] + '<MessageIncrement>0</MessageIncrement>' + scen_xml[mi_end + len('</MessageIncrement>'):] 
    return scen_xml, scen_name 